mapper.select:
SELECT sl.id AS id, sl.school_id AS schoolId, sl.school_year AS schoolYear, grade.id AS gradeId, grade.grade_group_name AS gradeName, sl.class_id AS classId, cla.class_name AS className, sl.student_id AS studentId, stu.chinese_name AS studentName, stu.seat_no AS seatNo, sl.leave_date AS leaveDate, sl.leave_type AS leaveType, sl.periods AS periods, sl.remark AS remark, sl.registrant_id AS registrantId, sl.registrant_name AS registrantName, sl.registrant_type AS registrantType FROM student_leave sl LEFT JOIN student_info stu ON stu.id = sl.student_id LEFT JOIN sys_class cla ON cla.id = sl.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group WHERE sl.deleted = 0
AND sl.school_id = #{reqModel.schoolId}
AND sl.school_year = #{reqModel.schoolYear}
AND sl.class_id = #{reqModel.classId}
AND sl.class_id IN
#{classId}
AND sl.student_id = #{reqModel.studentId}
AND sl.leave_type = #{reqModel.leaveType}
AND sl.leave_date = #{reqModel.leaveDate}
AND sl.class_id IN
#{classId}
ORDER BY id DESC

SELECT student_id as studentId, leave_type as leaveType, SUM(periods) as totalPeriods FROM student_leave WHERE school_id = #{schoolId} AND deleted = 0
AND class_id = #{classId}
AND student_id IN
#{studentId}
GROUP BY student_id, leave_type
